.app {
  height: calc(var(--appsmith-ui-height) * 1px);
  width: calc(var(--appsmith-ui-width) * 1px);
  overflow-y: auto;
  overflow-x: hidden;
  font-family: "Nunito", "Inter", sans-serif;
  background: #f8fafc;
  box-sizing: border-box;
  padding: 0;
}

.ctip {
  position: fixed;
  background: #1e293b;
  color: #fff;
  font-size: 11px;
  padding: 5px 9px;
  border-radius: 6px;
  pointer-events: none;
  z-index: 99999;
  max-width: 280px;
  white-space: pre-wrap;
  display: none;
}

.ctip.show {
  display: block;
}

